-- в”Ђв”Ђ XBackBone в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$XBackBone is a free, open-source, self-hosted file and media sharing server with full ShareX support, letting teams run their own private alternative to third-party image and file hosts.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, open source)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$XBackBone Review 2026: Free Self-Hosted File Sharing Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$XBackBone is an open-source, self-hosted file and screenshot sharing server with ShareX support. See its features, deployment options, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$XBackBone is an open-source, self-hosted file and media sharing application originally created by developer SergiX44, with its GitHub repository dating to 2018. It is designed as a lightweight, privately hosted alternative to third-party image and file hosting services such as Imgur, Lightshot, or CloudApp, and is most commonly paired with ShareX, the popular Windows screen-capture tool, though it works as a general-purpose file host as well. The application supports uploading images, GIFs, video, audio, PDFs, code snippets, and arbitrary files, generating clean short links with rich social embed previews. It provides inline previews for images, video, audio (including waveform display), PDFs, and syntax-highlighted code, plus dedicated paste and link-shortening features. Files are de-duplicated by content fingerprint, so identical uploads are stored only once, reducing storage overhead on self-hosted instances. XBackBone supports pluggable storage backends, including local disk, Amazon S3 and other S3-compatible services, and FTP/SFTP, and instances can switch between backends without disrupting the existing data model. On the access-control side, XBackBone offers per-resource visibility settings with optional password protection and automatic link expiration, along with account security features including two-factor authentication and WebAuthn passkey support. Administrators get multi-user management with per-user disk quotas, usage statistics, and admin roles, plus a versioned REST API with auto-generated OpenAPI documentation for programmatic integrations. Deployment is handled either through Docker or a traditional LAMP stack (PHP and MySQL), making it accessible to self-hosters running a home server, VPS, or small internal infrastructure. Because it is fully open source and self-hosted, there is no vendor subscription cost; the only ongoing expense is whatever server or storage infrastructure a user chooses to run it on. XBackBone is best suited for privacy-conscious individuals, dev teams, and small organizations that want full control over where their screenshots, files, and shared links live, rather than depending on a third-party hosted service.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ee29016b-e8bd-48bb-949d-e74570770e58';

