INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Keyword Explorer and Golden Ratio Filters$q$, $q$Surfaces search volume, competition, and Keyword Golden Ratio filters to uncover low-competition keyword opportunities.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Topic Discovery and Clustering$q$, $q$Groups related keywords into topic clusters and content pillars to guide a structured content calendar.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$NLP-Powered Content Editor$q$, $q$Analyzes the top 20 ranking competitor pages for a keyword and recommends terms, headings, and outline structure inside the writing editor.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$AI Writing Assistant$q$, $q$Generates and expands article drafts within the same editor used for keyword and NLP guidance, avoiding tool-switching.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Plagiarism Checker$q$, $q$Scans drafts for duplicate content before publishing, included unlimited on the All-In-One plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Allintitle Data$q$, $q$Reports exact-match title competition for a keyword, a metric many mainstream SEO tools omit.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Rank Tracking$q$, $q$Monitors keyword rankings over time to measure the impact of published content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Team Collaboration$q$, $q$Supports multiple member seats and shared keyword lists for agencies and in-house teams working across client accounts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$One-time purchase pricing avoids the recurring subscription costs common among SEO suites.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Combines keyword research, clustering, and AI writing in a single dashboard, reducing tool switching.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$NLP-based competitor analysis gives concrete, actionable outline suggestions rather than generic keyword lists.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Keyword Golden Ratio and Allintitle filters help surface low-competition opportunities other tools do not highlight.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Rated as one of the easier-to-use SEO content platforms on G2.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Google NLP analysis credits are sold separately and not included in the base plans.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Backlink analysis and technical SEO auditing are far less developed than in Ahrefs or Semrush.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$One-time pricing plans come with fixed keyword and clustering credit caps that heavy users can exhaust.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Smaller ecosystem and community support than category leaders.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Is WriterZen a one-time purchase or a subscription?$q$, $q$WriterZen's core plans (Keyword Research, All-In-One Basic, All-In-One Advanced) are sold as one-time purchases, though extra team seats and NLP or keyword credits are billed as ongoing add-ons.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Does WriterZen include AI content writing?$q$, $q$Yes, unlimited AI writing is included on the All-In-One Basic and All-In-One Advanced plans, alongside an NLP-guided outline editor.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$What is the Keyword Golden Ratio filter?$q$, $q$It is a filter that surfaces keywords with high search volume relative to low Allintitle competition, helping identify ranking opportunities that are easier to compete for.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Can WriterZen replace Ahrefs or Semrush?$q$, $q$It can replace them for keyword research, clustering, and content creation workflows, but it does not offer the same depth of backlink analysis or technical site auditing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Who founded WriterZen?$q$, $q$WriterZen was founded in 2021 by Daniel Nguyen, an SEO content agency operator based in Singapore.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Does WriterZen check for plagiarism?$q$, $q$Yes, a plagiarism checker is included and unlimited on the All-In-One plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Can multiple team members use one WriterZen account?$q$, $q$Yes, additional member seats can be added for 9 dollars per seat per month, with collaborative keyword lists and content tracking.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Is there a free trial?$q$, $q$WriterZen has offered free trials on some subscription-style plans in the past; current availability should be confirmed on writerzen.net before purchasing.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$SEO Content Agencies$q$, $q$Agencies managing keyword research and content production for multiple clients use WriterZen's clustering and collaboration features to organize work by account.$q$, $q$SEO and content marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Solo SEO Consultants$q$, $q$Independent consultants use the one-time pricing plans to access keyword research and AI writing without committing to a recurring subscription.$q$, $q$Freelance SEO consultants and bloggers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$In-House Marketing Teams$q$, $q$Marketing teams at SMBs use WriterZen to plan content clusters and draft NLP-optimized articles without maintaining separate research and writing subscriptions.$q$, $q$In-house marketing and content teams at small and mid-sized businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$Keyword Research$q$, $q$$135$q$, $q$one-time$q$, NULL, $q$["50,000 keyword credits","10,000 keywords clustering","50 keyword lists","50 keywords lookup","Keyword Golden Ratio filter","Revenue forecast"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$All-In-One Basic$q$, $q$$270$q$, $q$one-time$q$, NULL, $q$["50,000 keyword credits","10,000 keywords clustering","50 articles per month","Unlimited AI writing","Unlimited plagiarism checking","Team collaboration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$All-In-One Advanced$q$, $q$$405$q$, $q$one-time$q$, NULL, $q$["100,000 keyword credits","20,000 keywords clustering","100 articles per month","Unlimited AI writing and plagiarism checking","Unlimited keyword and topic lookup","2 extra member seats included"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$overview$q$, $q$What Is WriterZen$q$, 2, ARRAY[$q$WriterZen is a content workflow platform built specifically for SEO teams, combining the research, planning, and writing stages of content production into one interface rather than requiring separate keyword, clustering, and writing tools.$q$, $q$Founded in 2021 by Daniel Nguyen and based in Singapore, WriterZen grew out of the founder's experience running an SEO content agency, where he found that generic writing assistants lacked the keyword and competitor context that ranking content actually requires.$q$, $q$The platform is aimed at SEO consultants, content agencies, and in-house marketing teams who want a single dashboard for topic research, clustering, and AI-assisted drafting without paying for multiple point solutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$WriterZen's Keyword Explorer surfaces search volume, competition, and Keyword Golden Ratio data to help identify low-competition, high-opportunity keywords, while the Topic Discovery module groups related terms into content clusters and pillar pages.$q$, $q$The Content Creator editor runs NLP analysis against the top 20 competing pages for a target keyword and suggests terms, headings, and paragraph structure to include, alongside a built-in plagiarism checker and unlimited AI writing on the All-In-One plans.$q$, $q$Additional capabilities include Allintitle data for gauging exact-match title competition, keyword rank tracking, and team collaboration features for agencies managing multiple client accounts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d9bbada-62bd-4fae-b98c-356fa0441d5f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WriterZen breaks from the subscription norm common among SEO tools by selling its core plans as one-time purchases: Keyword Research at 135 dollars, All-In-One Basic at 270 dollars, and All-In-One Advanced at 405 dollars.$q$, $q$Each one-time plan includes a bundle of keyword credits, clustering allowances, and keyword list limits, with the All-In-One tiers adding unlimited AI writing and plagiarism checking plus a set number of articles per month.$q$, $q$Google NLP analysis credits and extra team member seats (9 dollars per seat per month) are purchased separately, so ongoing costs depend on usage rather than being fixed into a flat monthly subscription.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$AI Article Writer$q$, $q$Generates long-form SEO content using multiple selectable language models including GPT-4o, Claude, and Gemini.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$AI Search Visibility Tracking$q$, $q$Monitors how a brand is mentioned and represented in answers from ChatGPT, Gemini, and Google AI Overviews.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Chatsonic$q$, $q$A conversational AI assistant for research, brainstorming, and quick content generation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$SEO Checker and Site Audits$q$, $q$Scans pages for on-page SEO issues and produces audit reports across hundreds to thousands of pages depending on plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Action Center$q$, $q$Surfaces recommended on-page and off-page fixes and, on higher plans, can execute limited automated actions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Botsonic$q$, $q$A no-code tool for building custom AI chatbots trained on a business's own content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Multi-Model Access$q$, $q$Lets users choose between GPT-4o, Claude, and Gemini for content generation within the same workspace.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Combines AI writing with AI-search visibility tracking, a category most competitors do not yet cover.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Access to multiple leading language models rather than being locked to one provider.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Free plan lets teams evaluate the platform before committing to a paid tier.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Broader ecosystem (chatbots, text-to-speech, research assistant) reduces need for separate point tools.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Entry-level paid pricing at 79 dollars a month is higher than many single-purpose AI writing tools.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Full Action Center automation and all-platform AI visibility tracking are reserved for Growth and Enterprise tiers.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$The growing feature set can feel overwhelming for users who just want a simple article generator.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$AI-generated drafts still typically require human editing before publishing.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$What does Writesonic do?$q$, $q$Writesonic is an AI content platform that generates SEO articles, ad copy, and other marketing content, and also tracks how a brand is represented in answers from AI search tools like ChatGPT and Gemini.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Does Writesonic have a free plan?$q$, $q$Yes, Writesonic offers a free plan that does not require a credit card, though with reduced limits compared to paid tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Which AI models does Writesonic use?$q$, $q$Writesonic gives users access to multiple models, including GPT-4o, Claude, and Gemini, rather than relying on a single proprietary model.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$What is AI search visibility tracking?$q$, $q$It monitors how frequently and favorably a brand appears in answers generated by AI platforms such as ChatGPT, Gemini, and Google AI Overviews, a practice often called Generative Engine Optimization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$How much does Writesonic cost?$q$, $q$Paid plans start at 79 dollars per month for Starter (billed annually) and scale up to 399 dollars per month for Growth, with custom Enterprise pricing above that.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Who founded Writesonic?$q$, $q$Writesonic was founded by Samanyou Garg, launching around 2020 before rebranding from its original name, Magicflow.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Is Writesonic suited for solo bloggers?$q$, $q$It can be used by solo creators, but its current pricing and feature set are built primarily for marketing teams that need both content generation and AI-search visibility monitoring.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Content Marketing Teams$q$, $q$Teams use the AI Article Writer and SEO Checker to produce and optimize blog content at scale across multiple language models.$q$, $q$Content marketing and demand generation teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Brand and Digital Marketing Managers$q$, $q$Marketers track how their brand is represented in ChatGPT, Gemini, and AI Overview answers, then use the Action Center to address visibility gaps.$q$, $q$Brand marketing and SEO managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Agencies Managing Multiple Clients$q$, $q$Agencies use multi-project and multi-user plans to generate content and monitor AI search visibility across several client accounts at once.$q$, $q$Digital marketing and SEO agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Limited AI platform tracking","Limited AI articles","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Starter$q$, $q$$79/month$q$, $q$monthly, billed annually ($948/year)$q$, NULL, $q$["Tracks 3 AI platforms","50 prompts and 50 answers tracked daily","15 AI articles per month","10 site audits (100 pages each)","1 user, 1 project"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Basic$q$, $q$$199/month$q$, $q$monthly, billed annually ($2,388/year)$q$, NULL, $q$["100 prompts and 300 answers tracked daily","25 AI articles per month","20 site audits (1,200 pages each)","2 users, 1 project"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Growth$q$, $q$$399/month$q$, $q$monthly, billed annually ($4,788/year)$q$, NULL, $q$["200 prompts and 600 answers tracked daily","Sentiment analysis included","50 AI articles per month","Action Center trial (5 off-page and 5 on-page actions per month)","3 users, 2 projects"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Tracks all 10 supported AI platforms","Custom prompts, regions, and languages","Full Action Center and agentic workflows","SSO/SAML support","Dedicated AI search strategist"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$overview$q$, $q$What Is Writesonic$q$, 2, ARRAY[$q$Writesonic launched in 2020 as an AI writing assistant, founded by Samanyou Garg, and has grown from a single article generator into a broader AI content and marketing platform headquartered in San Francisco.$q$, $q$The product line now spans AI Article Writer, Chatsonic for conversational research, Botsonic for chatbot building, and Audiosonic for text-to-speech, unified under one account.$q$, $q$Its most notable recent shift is toward Generative Engine Optimization, tracking how brands are represented in answers from ChatGPT, Gemini, and Google AI Overviews alongside traditional SEO content generation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The AI Article Writer produces long-form, SEO-oriented content using access to multiple language models including GPT-4o, Claude, and Gemini, rather than a single proprietary model.$q$, $q$AI visibility tracking monitors brand mentions and sentiment across major AI chat and search platforms, giving marketing teams data on how they appear in AI-generated answers.$q$, $q$The SEO Checker and Optimizer, combined with site audits and an Action Center for on-page and off-page fixes, extends the platform beyond writing into broader search optimization workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Writesonic offers a free plan with no credit card required, alongside four paid tiers: Starter, Basic, Growth, and Enterprise.$q$, $q$Starter costs 79 dollars per month billed annually and covers tracking of three AI platforms, 15 AI articles per month, and 10 site audits for a single user.$q$, $q$Growth, at 399 dollars per month, is positioned as the most popular tier, adding sentiment analysis and a trial of automated on-page and off-page Action Center fixes for up to three users, while Enterprise pricing is custom and unlocks all 10 tracked AI platforms and SSO support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Drag-and-Drop Form Builder$q$, $q$Build forms visually with a range of field types without writing HTML or code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Conditional Logic$q$, $q$Configure up to 50 rules to show, hide, or branch form fields and pages based on user responses.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Payment Integrations$q$, $q$Accept payments directly through forms via Stripe, PayPal, Braintree, Authorize.Net, and other processors.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$400+ Templates$q$, $q$Start from pre-built templates for registrations, orders, surveys, and feedback forms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Reporting and Analytics$q$, $q$Generate unlimited reports from form entries to visualize response data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$File Upload Fields$q$, $q$Let respondents attach files directly within a form, with storage limits scaling by plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Field Encryption and Password Protection$q$, $q$Protect sensitive form data with encryption and restrict access on higher-tier plans.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Long operating history (since 2006) and Momentive/SurveyMonkey backing provide platform stability.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Strong conditional logic supports genuinely complex, branching forms.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Wide range of native payment processor integrations for collecting payments directly.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Generous free plan for light, low-volume use cases.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$400+ templates speed up building common form types.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Free and entry-level plans cap forms, entries, and fields fairly tightly compared to some competitors.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Interface and design options are frequently described by reviewers as dated compared to newer builders.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$No native AI-assisted form generation, unlike several newer entrants in the category.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Higher-volume plans (Advanced, Ultimate) get expensive relative to entry-level competitors.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Is Wufoo free to use?$q$, $q$Yes, Wufoo offers a free plan limited to 5 forms, 100 entries per month, 10 fields, and 1 user.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Who owns Wufoo?$q$, $q$Wufoo has been owned by SurveyMonkey, now operating as Momentive, since it acquired the company in 2011.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Can Wufoo accept online payments?$q$, $q$Yes, Wufoo integrates with Stripe, PayPal, Braintree, Authorize.Net, Chargify, USA ePay, and FreshBooks to collect payments directly through forms.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$How much does Wufoo cost?$q$, $q$Paid plans range from 16.25 dollars per month (Starter, billed annually) up to 210.25 dollars per month (Ultimate), based on form, entry, and user limits.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Does Wufoo support conditional logic?$q$, $q$Yes, forms can use up to 50 rules to show, hide, or branch fields and pages based on earlier responses.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$When was Wufoo founded?$q$, $q$Wufoo was founded in 2006 in Tampa, Florida by Kevin Hale, Chris Campbell, and Ryan Campbell.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$How many templates does Wufoo offer?$q$, $q$Wufoo provides more than 400 ready-made form templates covering registrations, orders, surveys, and more.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Small Business Lead and Order Forms$q$, $q$Small businesses use Wufoo to build contact, order, and payment forms with conditional logic without hiring a developer.$q$, $q$Small business owners and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Nonprofit Registration and Donations$q$, $q$Nonprofits use Wufoo's payment integrations and templates to collect event registrations and donations online.$q$, $q$Nonprofits and community organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Internal Data Collection Forms$q$, $q$Teams use Wufoo to build internal intake, request, and feedback forms with reporting built in.$q$, $q$Operations and HR teams at small and mid-sized companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["5 forms","100 entries per month","10 fields","1 user","Unlimited reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Starter$q$, $q$$16.25/month$q$, $q$annual ($195/year)$q$, NULL, $q$["10 forms","1,000 entries per month","Max fields","File uploads","Custom logo and integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Professional$q$, $q$$33.25/month$q$, $q$annual ($399/year)$q$, NULL, $q$["Unlimited forms","5,000 entries per month","5 users","Payment acceptance","Field encryption and password protection"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Advanced$q$, $q$$83.25/month$q$, $q$annual ($999/year)$q$, NULL, $q$["25,000 entries per month","20 users","10GB file storage","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$Ultimate$q$, $q$$210.25/month$q$, $q$annual ($2,523/year)$q$, NULL, $q$["200,000 entries per month","60 users","20GB file storage","Priority support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$overview$q$, $q$What Is Wufoo$q$, 2, ARRAY[$q$Wufoo is a web-based form builder founded in 2006 in Tampa, Florida, letting users create contact forms, surveys, registrations, and payment forms without writing code.$q$, $q$SurveyMonkey (Momentive) acquired Wufoo in 2011 for roughly 35 million dollars, and it continues to operate as a standalone product within Momentive's suite of survey and data-collection tools.$q$, $q$The platform targets small businesses, nonprofits, and teams that need dependable, no-code forms rather than a full survey research platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Conditional logic supports up to 50 form rules, letting builders show or hide fields, branch to different pages, or adjust the form flow based on earlier answers.$q$, $q$Built-in payment integrations connect directly to Stripe, PayPal, Braintree, Authorize.Net, Chargify, USA ePay, and FreshBooks so forms can collect payments or donations without extra tooling.$q$, $q$Over 400 ready-made templates cover common use cases such as event registration, order forms, and feedback surveys, speeding up initial setup.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wufoo offers a free plan limited to 5 forms, 100 entries per month, 10 fields, and 1 user, suitable for very light use.$q$, $q$Paid tiers scale from Starter at 16.25 dollars per month (billed annually) up to Ultimate at 210.25 dollars per month, with each tier raising the caps on forms, monthly entries, file storage, API requests, and team seats.$q$, $q$Payment acceptance, higher file upload limits, and field encryption are unlocked starting on the Professional tier at 33.25 dollars per month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('106def15-bc26-47dd-b9c7-dbb691ff1a8c', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Compensation Configurator$q$, $q$Build commission plans from reusable rules, quotas, and rate tables rather than custom-coding each plan variant.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$100+ Out-of-the-Box Reports$q$, $q$Prebuilt and customizable dashboards give finance and sales leadership visibility into compensation performance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Plan Document and Workflow Management$q$, $q$Track, configure, and manage compensation plan approvals and changes throughout the plan lifecycle.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Rep and Manager Self-Service Dashboards$q$, $q$Give sales reps and managers on-demand visibility into projected and actual commission payouts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$CRM, ERP, and HCM Integrations$q$, $q$Connects with Salesforce, Microsoft Dynamics, NetSuite, and other systems to pull deal and quota data automatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$AI-Assisted Plan Optimization$q$, $q$Uses Xactly's proprietary compensation data to suggest plan design improvements.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Dispute and Exception Management$q$, $q$Provides tools to track and resolve commission disputes and calculation exceptions.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Handles highly complex, multi-tier commission structures that spreadsheets and simpler tools cannot reliably support.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Deep native integrations with major CRM, ERP, and HCM platforms reduce manual data entry.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Extensive reporting and dashboard options give both leadership and individual reps payout visibility.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Reduces commission calculation errors and disputes compared to manual processes.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Pricing is not publicly listed and requires a sales demo and custom quote.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Implementation fees can add tens to well over a hundred thousand dollars on top of subscription costs.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Steeper learning curve than simpler commission tools, given its configurability.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Overkill and cost-prohibitive for very small sales teams with simple, flat commission plans.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$What does Xactly Incent do?$q$, $q$Xactly Incent automates the design, calculation, and reporting of sales commission plans for revenue operations and finance teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$How much does Xactly Incent cost?$q$, $q$Xactly does not publish flat pricing; costs are quoted individually, though mid-market Incent contracts have been reported between 36,000 and 216,000 dollars per year depending on team size.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Does Xactly offer a self-serve option for smaller teams?$q$, $q$Yes, Xactly's SimplyComp product is a do-it-yourself option for teams of up to 25 reps, reported at around 40 dollars per user per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$What CRM systems does Xactly Incent integrate with?$q$, $q$It integrates with major CRM, ERP, and HCM systems including Salesforce, Microsoft Dynamics, and NetSuite.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$When was Xactly Corporation founded?$q$, $q$Xactly was founded in 2005 and is headquartered in San Jose, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Is there an implementation cost beyond the subscription?$q$, $q$Yes, implementation and professional services are quoted separately and can range from roughly 15,000 to over 150,000 dollars depending on complexity.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Who is Xactly Incent best suited for?$q$, $q$It is best suited for medium to large enterprises with complex, multi-tier sales commission structures and larger sales teams.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Enterprise Commission Automation$q$, $q$Revenue operations teams replace error-prone spreadsheets with automated commission calculations tied directly to CRM data.$q$, $q$Enterprise RevOps and sales finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Multi-Tier Sales Compensation Design$q$, $q$Compensation analysts use the Configurator to build and adjust complex, multi-tier commission plans across large sales organizations.$q$, $q$Compensation and sales operations analysts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Sales Rep Payout Transparency$q$, $q$Sales leaders give reps self-service visibility into projected commissions to reduce disputes and improve trust in the compensation process.$q$, $q$Sales managers and individual sales representatives$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$SimplyComp$q$, $q$~$40/user/month$q$, $q$annual$q$, NULL, $q$["Self-serve, DIY setup","Designed for teams up to 25 reps","Basic commission calculation and reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Incent (Mid-Market)$q$, $q$$36,000 to $216,000/year$q$, $q$annual contract$q$, NULL, $q$["For 50 to 300 sales reps","Compensation Configurator","100+ reports and dashboards","CRM/ERP/HCM integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$Enterprise$q$, $q$Custom quote$q$, $q$custom$q$, NULL, $q$["Large-scale, highly complex compensation plans","Dedicated implementation and support","Advanced integrations and AI plan optimization"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$overview$q$, $q$What Is Xactly Incent$q$, 2, ARRAY[$q$Xactly Incent is the core incentive compensation management product from Xactly Corporation, a sales performance management vendor founded in 2005 and headquartered in San Jose, California.$q$, $q$The platform automates commission plan design, calculation, and payout reporting, replacing spreadsheet-based processes that are common in sales organizations before they adopt dedicated compensation software.$q$, $q$It is aimed primarily at revenue operations, sales finance, and compensation teams at medium to large enterprises managing complex, multi-tier commission structures.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Compensation Configurator lets teams build commission plans from reusable rules, quotas, and rate tables, with AI-assisted optimization suggestions drawn from Xactly's compensation data.$q$, $q$More than 100 out-of-the-box reports and customizable dashboards give sales and finance leadership visibility into plan performance, while rep and manager dashboards provide on-demand payout transparency.$q$, $q$Deep integrations with CRM, ERP, and HCM systems such as Salesforce, Microsoft Dynamics, and NetSuite let commission calculations pull directly from deal, quota, and payroll data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be3d358d-02c4-42e2-b373-1d918d655065', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Xactly does not publish flat, self-serve pricing for Incent; most deployments are sold through a custom quote after a product demonstration.$q$, $q$Xactly's DIY product, SimplyComp, aimed at teams of up to 25 reps, has been reported at around 40 dollars per user per month.$q$, $q$Mid-market Incent contracts for 50 to 300 reps have been reported between 36,000 and 216,000 dollars per year, with separate implementation fees ranging from roughly 15,000 to over 150,000 dollars depending on complexity.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Copy-on-Write Branching$q$, $q$Create instant Postgres branches that share unchanged data with their parent, avoiding full-dataset duplication.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Scale-to-Zero Compute$q$, $q$Idle databases stop incurring compute charges while data remains intact, with fast wake-up times on Cloud.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Native Postgres Compatibility$q$, $q$Supports the standard Postgres wire protocol alongside SQL over HTTP, working with existing drivers and ORMs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Multi-AZ High Availability$q$, $q$Read replicas across multiple availability zones with automatic failover for production workloads.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Open-Source Self-Hosting$q$, $q$The Apache 2.0-licensed core can be self-hosted for free, independent of Xata's managed cloud.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Bring Your Own Cloud (BYOC)$q$, $q$Deploys Xata into a customer's own AWS, Azure, or GCP account for enterprises with strict compliance needs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$SOC 2 and GDPR Compliance$q$, $q$Xata Cloud is SOC 2 and GDPR compliant, with BYOC additionally supporting HIPAA-ready anonymization and signed BAAs.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Near-instant database branching supports fast preview environments and safer schema migrations.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Full Postgres wire protocol compatibility avoids vendor lock-in to a proprietary query layer.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Usage-based pricing means costs scale with actual compute and storage consumption.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Open-source core gives teams a free, self-hosted path independent of the managed cloud.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$No permanent free tier on the managed Cloud product since the 2024-2025 platform rebuild.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Usage-based billing can be harder to predict than flat subscription pricing for budgeting.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$The 2024-2025 product pivot means a shorter track record for the current Postgres-focused platform compared to established managed Postgres providers.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$BYOC pricing requires contacting sales rather than self-serve signup.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$What is Xata?$q$, $q$Xata is a serverless Postgres database platform that offers instant, git-like database branching along with scale-to-zero compute.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Is Xata open source?$q$, $q$Yes, Xata's core database engine is licensed under Apache 2.0 and can be self-hosted for free.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$How does Xata pricing work?$q$, $q$Xata Cloud is billed usage-based, roughly 0.012 dollars per hour of compute plus 0.28 dollars per gigabyte of storage monthly, while BYOC is custom-quoted.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Is Xata compatible with standard Postgres tools?$q$, $q$Yes, Xata supports the native Postgres wire protocol as well as SQL over HTTP, so existing drivers and clients work without modification.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Who founded Xata?$q$, $q$Xata was founded in December 2020 by Monica Sarbu, with Tudor Golubenco as CTO, and is based in San Francisco.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$What is database branching used for on Xata?$q$, $q$It lets teams create isolated copies of a database for development, testing, or preview environments without duplicating the full dataset, using copy-on-write storage.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Does Xata support enterprise compliance requirements?$q$, $q$Xata Cloud is SOC 2 and GDPR compliant, and the BYOC tier adds HIPAA-ready anonymization and signed BAAs.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Preview Environments for Pull Requests$q$, $q$Engineering teams spin up a fresh database branch for every pull request to test changes against realistic data without affecting production.$q$, $q$Software engineering and platform teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Safer Schema Migrations$q$, $q$Teams branch the database before applying schema changes, validate the migration on the branch, then merge or discard it.$q$, $q$Backend engineers and database administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Regulated Enterprise Deployments$q$, $q$Enterprises with compliance requirements deploy Xata via BYOC into their own cloud account to keep data within their security perimeter.$q$, $q$Enterprise platform and security teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Open Source$q$, $q$$0$q$, $q$self-hosted$q$, NULL, $q$["Apache 2.0 licensed core","Branching and scale-to-zero included","Community support only","Self-managed provisioning"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$Xata Cloud$q$, $q$From ~$9/month (micro instance) plus $0.28/GB storage$q$, $q$usage-based$q$, NULL, $q$["Fully managed provisioning","~1 second wake-up time","SOC 2 and GDPR compliance","Multi-region on AWS and GCP","Standard support with observability"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$BYOC$q$, $q$Custom quote$q$, $q$custom$q$, NULL, $q$["Deploys in customer's own cloud account","HIPAA-ready anonymization","24/7 dedicated support","Multi-cloud, multi-region support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$overview$q$, $q$What Is Xata$q$, 2, ARRAY[$q$Xata is a serverless Postgres platform founded in December 2020 by Monica Sarbu, with Tudor Golubenco as CTO, and is headquartered in San Francisco.$q$, $q$The company originally launched as an Airtable-style data platform, then rebuilt its product between 2024 and 2025 into a dedicated Postgres platform centered on instant database branching.$q$, $q$It targets engineering teams that want git-like workflows for their database: creating, testing, and discarding branches without duplicating full datasets.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Copy-on-write branching lets teams create near-instant Postgres branches that share data with their parent and only store the changes made, ideal for preview environments and safe schema testing.$q$, $q$Scale-to-zero compute separates storage from compute so idle databases stop accruing compute costs without losing data, while multi-availability-zone read replicas provide high availability.$q$, $q$Databases support the native Postgres wire protocol as well as SQL over HTTP, so existing Postgres tooling and drivers work without modification.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0dfbc077-2e6f-43bd-beb1-5237a10ecdd5', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Xata's open-source core is Apache 2.0-licensed and free to self-host, with community-only support and a roughly 10-second cold-start wake time.$q$, $q$Xata Cloud bills usage-based at about 0.012 dollars per hour of compute plus 0.28 dollars per gigabyte of storage per month, with an always-on micro instance costing roughly 9 dollars monthly.$q$, $q$BYOC (Bring Your Own Cloud) deploys into a customer's own cloud account under a custom quote, aimed at enterprises needing HIPAA-ready compliance and dedicated 24/7 support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$ShareX Integration$q$, $q$One-click configuration for the ShareX screen-capture tool, enabling instant upload of screenshots to a private server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Multi-Format File Support$q$, $q$Handles images, GIFs, video, audio, PDFs, code snippets, pastes, and arbitrary files with inline previews.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Content De-Duplication$q$, $q$Identical files are fingerprinted and stored only once, reducing storage use across an instance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Pluggable Storage Backends$q$, $q$Supports local disk, Amazon S3 and S3-compatible services, and FTP/SFTP without changing the underlying data model.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Access Control and Expiration$q$, $q$Per-resource visibility settings support optional password protection and automatic link expiration.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Two-Factor Auth and Passkeys$q$, $q$Account security includes two-factor authentication and WebAuthn passkey login support.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Versioned REST API$q$, $q$Provides a token-authenticated API with auto-generated, per-instance OpenAPI documentation.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Completely free and open source, with no subscription or per-user licensing cost.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Full ShareX compatibility makes it a near drop-in replacement for hosted screenshot services.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Flexible storage backend options, including S3-compatible cloud storage, suit a range of infrastructure setups.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Strong privacy and access controls, including 2FA, passkeys, password-protected links, and link expiration.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Requires self-hosting and basic server administration skills, unlike plug-and-play SaaS alternatives.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$No official managed or cloud-hosted version is offered by the project.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Community-maintained development pace can be slower than that of funded commercial competitors.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Uptime, backups, and security patching responsibility rests entirely on the self-hoster.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$What is XBackBone used for?$q$, $q$XBackBone is a self-hosted server for uploading and sharing screenshots, images, and files through short links, commonly paired with the ShareX capture tool.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Is XBackBone free?$q$, $q$Yes, XBackBone is free and open source; the only cost is the server or storage infrastructure you host it on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Does XBackBone work with ShareX?$q$, $q$Yes, it offers one-click ShareX uploader configuration, making it a common self-hosted replacement for third-party screenshot hosts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$What storage options does XBackBone support?$q$, $q$It supports local disk storage, Amazon S3 and S3-compatible services, and FTP/SFTP, and can switch between them without affecting existing data.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$How do you deploy XBackBone?$q$, $q$XBackBone can be deployed via Docker or a traditional LAMP stack using PHP and MySQL.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Does XBackBone support multiple users?$q$, $q$Yes, it includes multi-user management with admin roles, per-user disk quotas, and usage statistics.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Does XBackBone have an API?$q$, $q$Yes, it provides a versioned REST API with token authentication and auto-generated OpenAPI documentation.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Private ShareX Screenshot Hosting$q$, $q$Developers and power users replace third-party screenshot hosts with a private XBackBone server for instant ShareX uploads.$q$, $q$Developers and IT power users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Team File and Media Sharing$q$, $q$Small teams self-host XBackBone to share images, videos, and documents internally via short links without relying on external file hosts.$q$, $q$Small development or creative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Privacy-Focused Self-Hosting$q$, $q$Privacy-conscious users run XBackBone on a home server or VPS to keep control of where their shared files and links are stored.$q$, $q$Self-hosting enthusiasts and privacy-focused individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$Free / Self-Hosted$q$, $q$$0$q$, $q$one-time setup, self-hosted$q$, NULL, $q$["Full source code access","Unlimited use on your own infrastructure","Docker or LAMP deployment","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$overview$q$, $q$What Is XBackBone$q$, 2, ARRAY[$q$XBackBone is an open-source, self-hosted file and media sharing server, originally created by developer SergiX44, with its project dating back to 2018 on GitHub.$q$, $q$It functions as a privately hosted alternative to third-party image and file hosts, and is most commonly used alongside ShareX, the popular Windows screen-capture utility, for one-click screenshot uploading.$q$, $q$Because it is open source and self-hosted, there is no vendor subscription, only the cost of the server infrastructure a user chooses to run it on.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Supports uploading images, GIFs, video, audio, PDFs, code, and arbitrary files, generating short links with rich social embed previews and inline previews for most file types.$q$, $q$Files are de-duplicated by content fingerprint so identical uploads are stored only once, and storage can run on local disk, S3-compatible services, or FTP/SFTP.$q$, $q$Per-resource access control includes optional password protection and automatic link expiration, alongside account security via two-factor authentication and WebAuthn passkeys.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$XBackBone itself carries no license fee, since it is released as free, open-source software.$q$, $q$Users are responsible only for the cost of the server, VPS, or storage infrastructure they deploy it on, whether via Docker or a traditional LAMP (PHP/MySQL) stack.$q$, $q$There is no official managed or cloud-hosted version, so all costs and maintenance responsibility fall on whoever self-hosts the instance.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ee29016b-e8bd-48bb-949d-e74570770e58', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Automated Bank Feeds and Reconciliation$q$, $q$Connects to bank accounts to automatically import and reconcile transactions against the books.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Online Invoicing$q$, $q$Create, send, and track invoices with online payment acceptance and automated payment reminders.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$700+ App Marketplace$q$, $q$Integrates with a large ecosystem of third-party apps for payroll, payments, inventory, and industry-specific needs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Real-Time Financial Reporting$q$, $q$Customizable dashboards and reports give business owners and accountants up-to-date financial visibility.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Multi-Currency Accounting$q$, $q$Available on the Established plan, supporting businesses that transact in multiple currencies.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Project Tracking$q$, $q$Tracks time, costs, and profitability by project, included on the Established tier.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Mobile Apps$q$, $q$iOS and Android apps let business owners invoice, reconcile, and check financials on the go.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Unlimited Users$q$, $q$All Xero plans include unlimited user seats at no extra per-user cost, unlike many accounting competitors.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Unlimited users on every plan, unlike competitors that charge per seat.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Large, mature app marketplace with 700+ integrations extends functionality well beyond core accounting.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Real-time bank feeds and reconciliation reduce manual bookkeeping work.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Intuitive interface widely regarded as approachable for non-accountants.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Strong accountant and bookkeeper ecosystem, with many firms specializing in Xero setup and support.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Payroll functionality is limited or unavailable in some regions and often requires a separate add-on or third-party integration.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Multi-currency support, project tracking, and advanced analytics are locked behind the top Established tier.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Entry-level Early plan's invoice and bill caps can be restrictive for businesses that grow quickly.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Some users report slower customer support response times compared to premium-tier expectations.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$How much does Xero cost?$q$, $q$Xero's US plans start at 25 dollars per month for Early, 55 dollars per month for Growing, and 90 dollars per month for Established.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Does Xero limit the number of users?$q$, $q$No, all Xero plans include unlimited users at no additional per-seat cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$What is the difference between Xero's plans?$q$, $q$Early caps monthly invoices and bills, Growing removes those caps for unlimited invoicing, and Established adds multi-currency accounting, project tracking, and expense claims.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$When was Xero founded?$q$, $q$Xero was founded in 2006 in Wellington, New Zealand, where it remains headquartered.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Does Xero integrate with other business apps?$q$, $q$Yes, Xero connects to more than 700 third-party applications covering payroll, payments, inventory, and other business functions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Is Xero publicly traded?$q$, $q$Yes, Xero went public on the New Zealand Exchange in 2007 and later moved its primary listing to the Australian Securities Exchange in 2012.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Can Xero handle multiple currencies?$q$, $q$Multi-currency accounting is available on Xero's Established plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Is Xero available on mobile?$q$, $q$Yes, Xero offers mobile apps for iOS and Android in addition to its web application.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Freelancer and Sole Proprietor Bookkeeping$q$, $q$Freelancers and solo business owners use the Early plan to send invoices, track expenses, and reconcile bank transactions.$q$, $q$Freelancers, sole proprietors, and micro-businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Growing Small Business Accounting$q$, $q$Small businesses with increasing invoice volume move to the Growing or Established plan for unlimited invoicing, multi-currency support, and project tracking.$q$, $q$Small and mid-sized businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Bookkeeping and Accounting Firm Collaboration$q$, $q$Accounting and bookkeeping firms use Xero's unlimited-user model and real-time data access to collaborate directly with multiple small business clients.$q$, $q$Accounting and bookkeeping firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Early$q$, $q$$25/month$q$, $q$monthly$q$, NULL, $q$["Up to 20 invoices per month","Up to 5 bills per month","Bank reconciliation","Unlimited users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Growing$q$, $q$$55/month$q$, $q$monthly$q$, NULL, $q$["Unlimited invoicing and bills","Customizable dashboards","Financial health scorecards","Unlimited users"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$Established$q$, $q$$90/month$q$, $q$monthly$q$, NULL, $q$["Multi-currency accounting","Project tracking","Expense claims","180-day cash flow forecasting","Unlimited users"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$overview$q$, $q$What Is Xero$q$, 2, ARRAY[$q$Xero is a cloud-based accounting platform founded in 2006 in Wellington, New Zealand, where it remains headquartered, and has grown into a publicly traded company with roughly 6,200 employees worldwide.$q$, $q$The platform is built for small and mid-sized businesses, giving business owners, bookkeepers, and accountants a shared, real-time view of the books rather than working from periodically exchanged file backups.$q$, $q$Xero's growth has been driven in large part by its extensive third-party app marketplace, which connects the core accounting product to payroll, payments, inventory, and industry-specific tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Automated bank feeds pull transactions directly from connected bank accounts for streamlined reconciliation, reducing manual data entry.$q$, $q$Online invoicing lets businesses send invoices, track payment status, and accept online payments, paired with bill management and expense tracking on higher tiers.$q$, $q$The app marketplace connects Xero to more than 700 third-party business applications, extending functionality into payroll, CRM, inventory, and industry-specific workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab58553d-75b9-40f6-9b54-61fbab218754', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Xero's US pricing has three tiers: Early at 25 dollars per month, Growing at 55 dollars per month, and Established at 90 dollars per month, all including unlimited users.$q$, $q$Early caps usage at 20 invoices and 5 bills per month, making it suited to freelancers and very early-stage businesses, while Growing removes those caps entirely.$q$, $q$Established adds multi-currency accounting, project tracking, expense claims, and extended cash flow forecasting, and is required once a business needs any of those capabilities.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Automatic Screenshot Styling$q$, $q$Adds balanced padding, rounded window framing, and a matching background automatically after capture.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Smart Background Selection$q$, $q$Analyzes the screenshot to pick an appropriate solid, gradient, or image background.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Sensitive Data Redaction$q$, $q$Automatically detects and blurs emails, IP addresses, credit card numbers, API keys, and passwords.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Built-In Text Extraction$q$, $q$Uses Apple's Vision framework to let users copy text directly out of a captured screenshot.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Annotation Tools$q$, $q$Includes arrows, shapes, text, and blur tools for marking up screenshots after capture.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Social Media Presets$q$, $q$Provides sizing presets optimized for common social platforms like Twitter and LinkedIn.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Screenshot History$q$, $q$Keeps a history of recent captures for quick reuse or re-editing.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Extremely fast, roughly two-second capture-to-polished-image workflow.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$One-time purchase pricing with no ongoing subscription required.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Native macOS performance from a lightweight, focused app.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Built-in sensitive-data redaction is a thoughtful privacy feature not common in competing screenshot tools.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$High user satisfaction, with a reported 4.9-star rating among daily users.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$macOS only, with no Windows or Linux version.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Fewer advanced annotation and workflow features than some subscription competitors like CleanShot X.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$One-time price may not guarantee free access to future major version upgrades.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$As a small indie product, feature development pace depends on a single founder and small team.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Is Xnapper free?$q$, $q$Xnapper is free to use, but exported screenshots include a watermark unless you make a one-time purchase to remove it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$How much does Xnapper cost?$q$, $q$Xnapper's one-time pricing starts at 29.99 dollars for one Mac device (Basic), up to 49.99 dollars for three devices (Standard).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Who created Xnapper?$q$, $q$Xnapper was created in 2022 by indie developer Tony Dinh.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Does Xnapper work on Windows?$q$, $q$No, Xnapper is a native macOS application only.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Can Xnapper redact sensitive information?$q$, $q$Yes, it can automatically detect and blur emails, IP addresses, credit card numbers, API keys, and passwords in a screenshot.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Does Xnapper extract text from screenshots?$q$, $q$Yes, it uses Apple's built-in Vision framework to let users copy text directly out of a captured image.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Is Xnapper a subscription?$q$, $q$No, Xnapper uses one-time pricing to unlock watermark-free exports rather than a recurring subscription.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Social Media Screenshot Sharing$q$, $q$Creators and founders use Xnapper to quickly turn app or product screenshots into polished images for Twitter and LinkedIn posts.$q$, $q$Indie developers, founders, and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Product Documentation and Marketing$q$, $q$Product and marketing teams use Xnapper to produce consistent, professional-looking screenshots for landing pages, docs, and release notes.$q$, $q$Product marketers and technical writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Privacy-Conscious Screen Sharing$q$, $q$Users capturing screenshots that may contain sensitive data use Xnapper's automatic redaction before sharing images externally.$q$, $q$Support, IT, and security-conscious professionals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Free$q$, $q$$0$q$, $q$free$q$, NULL, $q$["Full feature access","Exports include a watermark"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Basic$q$, $q$$29.99$q$, $q$one-time$q$, NULL, $q$["Watermark removed","Licensed for 1 Mac device"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Personal$q$, $q$$39.99$q$, $q$one-time$q$, NULL, $q$["Watermark removed","Licensed for 2 Mac devices"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$Standard$q$, $q$$49.99$q$, $q$one-time$q$, NULL, $q$["Watermark removed","Licensed for 3 Mac devices"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$overview$q$, $q$What Is Xnapper$q$, 2, ARRAY[$q$Xnapper is a native macOS screenshot app created by indie developer Tony Dinh in 2022 to help creators turn plain screen captures into polished, shareable images.$q$, $q$The app was built out of Dinh's own need to regularly share attractive screenshots on Twitter and LinkedIn, a common pain point among indie developers and content creators.$q$, $q$It targets individual creators, founders, and product teams on macOS rather than enterprise design or documentation teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Screenshots are captured in about two seconds and automatically styled with balanced padding, a rounded window frame, and a smart-selected background or gradient.$q$, $q$A built-in redaction tool can automatically detect and blur sensitive data such as emails, API keys, credit card numbers, and passwords before an image is shared.$q$, $q$Apple's Vision framework powers built-in text extraction, letting users copy text directly out of a screenshot, alongside annotation tools like arrows, shapes, text, and blur.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75b7cec6-4a39-4456-8f5f-bb719bb42775', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Xnapper uses a freemium, one-time-payment model: the app is fully functional for free but exports carry a watermark until purchased.$q$, $q$Removing the watermark is a one-time purchase rather than a subscription, priced by the number of licensed Mac devices.$q$, $q$Current tiers are Basic at 29.99 dollars for one device, Personal at 39.99 dollars for two devices, and Standard at 49.99 dollars for three devices.$q$]::text[], 2);
